"use client";

import React, { useState } from "react";

export default function LoginPage() {
  const [username, setUsername] = useState("");
  const [password, setPassword] = useState("");
  const [role, setRole] = useState("Service Advisor");

  return (
    <div style={{
      position: "relative",
      minHeight: "100vh",
      width: "100vw",
      display: "flex",
      alignItems: "center",
      justifyContent: "center",
      fontFamily: "Arial, sans-serif",
      overflow: "hidden"
    }}>
      
      {/* 1. BLURRED BACKGROUND IMAGE (Change the URL inside quotes anytime!) */}
      <div style={{
        position: "absolute",
        inset: 0,
        backgroundImage: "linear-gradient(rgba(0, 0, 0, 0.55), rgba(0, 0, 0, 0.65)), url('https://images.unsplash.com/photo-1619642751034-765dfdf7c58e?q=80&w=2000')",
        backgroundSize: "cover",
        backgroundPosition: "center",
        filter: "blur(12px)",
        transform: "scale(1.1)",
        zIndex: -1
      }} />

      {/* 2. EYE-CATCHING GLASS LOGIN CARD */}
      <div style={{
        width: "100%",
        maxWidth: "420px",
        padding: "40px",
        borderRadius: "24px",
        backgroundColor: "rgba(15, 23, 42, 0.65)",
        backdropFilter: "blur(20px)",
        WebkitBackdropFilter: "blur(20px)",
        border: "1px solid rgba(255, 255, 255, 0.15)",
        boxShadow: "0 25px 50px -12px rgba(0, 0, 0, 0.5)",
        color: "#ffffff",
        boxSizing: "border-box",
        margin: "20px"
      }}>
        
        {/* Title Header */}
        <div style={{ textAlign: "center", marginBottom: "32px" }}>
          <h1 style={{ fontSize: "32px", fontWeight: "900", margin: "0 0 8px 0", trackingWide: "1px" }}>
            LIVE SERVICE BAY
          </h1>
          <p style={{ color: "#38bdf8", fontSize: "12px", fontWeight: "800", textTransform: "uppercase", margin: 0, letterSpacing: "1.5px" }}>
            Smart Workshop. Smart Service.
          </p>
        </div>

        {/* Login Form */}
        <form onSubmit={(e) => { e.preventDefault(); alert(`Logging in as ${role}`); }} style={{ display: "flex", flexDirection: "column", gap: "20px" }}>
          
          {/* Username */}
          <div>
            <label style={{ display: "block", fontSize: "14px", fontWeight: "800", marginBottom: "8px" }}>Username / Email</label>
            <input 
              type="text" 
              value={username} 
              onChange={(e) => setUsername(e.target.value)} 
              placeholder="Enter username or email" 
              style={{
                width: "100%", padding: "14px", borderRadius: "12px", border: "1px solid rgba(255,255,255,0.2)", backgroundColor: "rgba(0,0,0,0.4)", color: "#fff", fontSize: "15px", fontWeight: "600", outline: "none", boxSizing: "border-box"
              }} 
              required 
            />
          </div>

          {/* Password */}
          <div>
            <label style={{ display: "block", fontSize: "14px", fontWeight: "800", marginBottom: "8px" }}>Password</label>
            <input 
              type="password" 
              value={password} 
              onChange={(e) => setPassword(e.target.value)} 
              placeholder="Enter password" 
              style={{
                width: "100%", padding: "14px", borderRadius: "12px", border: "1px solid rgba(255,255,255,0.2)", backgroundColor: "rgba(0,0,0,0.4)", color: "#fff", fontSize: "15px", fontWeight: "600", outline: "none", boxSizing: "border-box"
              }} 
              required 
            />
          </div>

          {/* Access Role Dropdown */}
          <div>
            <label style={{ display: "block", fontSize: "14px", fontWeight: "800", marginBottom: "8px" }}>Access Role</label>
            <select 
              value={role} 
              onChange={(e) => setRole(e.target.value)} 
              style={{
                width: "100%", padding: "14px", borderRadius: "12px", border: "1px solid rgba(255,255,255,0.2)", backgroundColor: "#0f172a", color: "#fff", fontSize: "15px", fontWeight: "800", cursor: "pointer", boxSizing: "border-box"
              }}
            >
              <option value="Admin">Admin</option>
              <option value="Service Advisor">Service Advisor</option>
              <option value="Technician">Technician</option>
            </select>
          </div>

          {/* Forgot Password */}
          <div style={{ textAlign: "right" }}>
            <a href="#" style={{ color: "#38bdf8", fontSize: "13px", fontWeight: "700", textDecoration: "none" }}>
              forgot password?
            </a>
          </div>

          {/* Submit Button */}
          <button 
            type="submit" 
            style={{
              width: "100%", padding: "16px", marginTop: "10px", border: "none", borderRadius: "12px", backgroundColor: "#2563eb", color: "#fff", fontSize: "16px", fontWeight: "900", cursor: "pointer", boxShadow: "0 10px 15px -3px rgba(37, 99, 235, 0.3)", transition: "background 0.2s"
            }}
          >
            Validate User
          </button>
        </form>
      </div>
    </div>
  );
}